import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import { 
    Icon, Modal, Toast, AINeuralLoader, SnowOverlay, 
    CommandPaletteModal, FontSizeController, SparkleLoader 
} from './components/UI';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import RecallModal from './components/RecallModal';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import { 
    validateApiKey, generateAnalysis, fetchFullClauseText 
} from './services/geminiService';
import { 
    DEFAULT_AUDIT_INFO, MY_FIXED_KEYS, STANDARDS_DATA 
} from './constants';
import { 
    AuditInfo, AnalysisResult, ApiKeyProfile, Clause, StandardsData
} from './types';
import { cleanAndParseJSON } from './utils';

const App = () => {
    // Layout State
    const [sidebarWidth, setSidebarWidth] = useState(390);
    const [fontSizeScale, setFontSizeScale] = useState(1);

    // Data State
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState("");
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);

    // UI Modals State
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);
    const [showRecallModal, setShowRecallModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [showReferenceModal, setShowReferenceModal] = useState(false);
    const [showCommandPalette, setShowCommandPalette] = useState(false);

    const [referenceClause, setReferenceClause] = useState<Clause | null>(null);
    const [referenceText, setReferenceText] = useState({ en: "", vi: "" });
    const [isReferenceLoading, setIsReferenceLoading] = useState(false);

    // Logic State
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState("");
    const [toastMessage, setToastMessage] = useState<string | null>(null);

    // API Key Management
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [newKeyInput, setNewKeyInput] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);

    // Effects
    useEffect(() => {
        // Init Fixed Keys
        const profiles = MY_FIXED_KEYS.map((k, i) => ({
            id: `fixed-${i}`, label: `System Key ${i+1}`, key: k, status: 'valid', latency: 0, lastChecked: new Date().toISOString()
        } as ApiKeyProfile));
        setApiKeys(profiles);

        // Load session
        const saved = localStorage.getItem("iso_session_data");
        if (saved) {
             try {
                 const data = JSON.parse(saved);
                 setAuditInfo(data.auditInfo || DEFAULT_AUDIT_INFO);
                 setStandardKey(data.standardKey || "ISO 9001:2015");
                 setSelectedClauses(data.selectedClauses || []);
                 setEvidence(data.evidence || "");
             } catch(e) { console.error("Load error", e); }
        }
    }, []);

    useEffect(() => {
        // Auto-save
        const timer = setTimeout(() => {
            const data = { auditInfo, standardKey, selectedClauses, evidence };
            localStorage.setItem("iso_session_data", JSON.stringify(data));
        }, 2000);
        return () => clearTimeout(timer);
    }, [auditInfo, standardKey, selectedClauses, evidence]);

    // Handlers
    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        setIsCheckingKey(true);
        const res = await validateApiKey(newKeyInput);
        setIsCheckingKey(false);

        if (res.isValid) {
            setApiKeys(prev => [...prev, {
                id: Date.now().toString(),
                label: `Custom Key ${prev.length + 1}`,
                key: newKeyInput,
                status: 'valid',
                latency: res.latency,
                lastChecked: new Date().toISOString()
            }]);
            setNewKeyInput("");
            setToastMessage("API Key Added Successfully");
        } else {
            setToastMessage("Invalid API Key");
        }
    };

    const handleReferenceClause = async (c: Clause) => {
        setReferenceClause(c);
        setShowReferenceModal(true);
        setIsReferenceLoading(true);
        try {
            const text = await fetchFullClauseText({ code: c.code, title: c.title }, standards[standardKey].name);
            setReferenceText(text);
        } catch (e) {
            setReferenceText({ en: "Error loading text.", vi: "" });
        } finally {
            setIsReferenceLoading(false);
        }
    };

    const handleRunAnalysis = async () => {
        if (!evidence.trim()) { setToastMessage("Please provide evidence first."); return; }
        setIsAnalyzing(true);
        setLoadingMessage("Analyzing Compliance...");
        try {
            // Simplified call for fix
            const res = await generateAnalysis(
                `Analyze this evidence against ${standards[standardKey]?.name}: ${evidence}`, 
                "You are an expert auditor."
            );
            const parsed = cleanAndParseJSON(res);
            setAnalysisResult(Array.isArray(parsed) ? parsed : []);
        } catch (e) {
            setToastMessage("Analysis Failed");
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <div className={`flex h-screen w-full bg-gray-50 dark:bg-black text-slate-900 dark:text-slate-100 overflow-hidden font-sans transition-all duration-300`} style={{ fontSize: `${fontSizeScale}rem` }}>
            <Sidebar 
                isOpen={true} 
                width={sidebarWidth} 
                setWidth={setSidebarWidth} 
                standards={standards} 
                standardKey={standardKey} 
                setStandardKey={setStandardKey}
                auditInfo={auditInfo} 
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses} 
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={() => {}}
                onUpdateStandard={(std) => setStandards({...standards, [standardKey]: std})}
                onResetStandard={() => {}}
                onReferenceClause={handleReferenceClause}
                showIntegrityModal={showIntegrityModal}
                setShowIntegrityModal={setShowIntegrityModal}
            />

            <div className="flex-1 flex flex-col h-full relative overflow-hidden">
                {/* Main Content Placeholder - Reconstructing basic UI */}
                <div className="flex-1 p-6 overflow-y-auto custom-scrollbar">
                    <div className="max-w-5xl mx-auto space-y-6">
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800">
                             <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <Icon name="Wand2" className="text-indigo-500"/>
                                Evidence Workspace
                             </h2>
                             <textarea 
                                className="w-full h-64 p-4 bg-gray-50 dark:bg-slate-950 rounded-xl border border-gray-200 dark:border-slate-800 focus:ring-2 focus:ring-indigo-500/20 outline-none resize-none font-mono text-sm"
                                placeholder="Paste audit evidence here (interview notes, document text, etc.)..."
                                value={evidence}
                                onChange={e => setEvidence(e.target.value)}
                             />
                             <div className="mt-4 flex justify-end">
                                 <button 
                                    onClick={handleRunAnalysis}
                                    disabled={isAnalyzing}
                                    className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-500/30 transition-all active:scale-95 disabled:opacity-50 flex items-center gap-2"
                                 >
                                     {isAnalyzing ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>}
                                     {isAnalyzing ? "Analyzing..." : "Run AI Analysis"}
                                 </button>
                             </div>
                        </div>

                        {analysisResult && (
                            <div className="space-y-4">
                                <h3 className="text-lg font-bold">Analysis Results</h3>
                                {analysisResult.map((res, idx) => (
                                    <div key={idx} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-gray-100 dark:border-slate-800">
                                        <div className="flex justify-between items-start mb-2">
                                            <span className="font-bold text-indigo-600">{res.clauseId}</span>
                                            <span className={`px-2 py-1 rounded text-xs font-bold ${res.status === 'COMPLIANT' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{res.status}</span>
                                        </div>
                                        <p className="text-sm mb-2">{res.reason}</p>
                                        <p className="text-xs text-slate-500 bg-gray-50 dark:bg-slate-950 p-2 rounded">Suggestion: {res.suggestion}</p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {/* Floating Tools */}
                <div className="absolute top-4 right-4 flex gap-2">
                     <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(type: 'increase'|'decrease') => setFontSizeScale(s => type === 'increase' ? s + 0.05 : s - 0.05)} />
                     <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-200 dark:border-slate-800 text-slate-500 hover:text-indigo-500">
                        <Icon name="Settings" />
                     </button>
                </div>
            </div>

            {/* Modals */}
            <Modal isOpen={showSettingsModal} title="Settings & Neural Network" onClose={() => setShowSettingsModal(false)}>
                <div className="space-y-6">
                    <div className="bg-gray-50 dark:bg-slate-800 p-4 rounded-2xl border border-gray-100 dark:border-slate-700 dark:shadow-[inset_0_1px_3px_rgba(0,0,0,0.5)]">
                        <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">API Key Pool Management</h4>
                        <div className="flex gap-2 mb-4">
                            <input 
                                type="password" 
                                placeholder="Paste Google Gemini API Key here..." 
                                className="flex-1 p-3 bg-white dark:bg-black border-2 border-indigo-100 dark:border-indigo-900 rounded-xl text-sm font-bold text-slate-900 dark:text-white placeholder-slate-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/20 transition-all shadow-inner"
                                value={newKeyInput}
                                onChange={(e) => setNewKeyInput(e.target.value)}
                            />
                            <button onClick={handleAddKey} disabled={isCheckingKey} className="px-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs disabled:opacity-50 transition-colors shadow-lg shadow-indigo-500/30">
                                {isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Plus" size={20}/>}
                            </button>
                        </div>
                        <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar">
                             {apiKeys.map(k => (
                                 <div key={k.id} className="flex justify-between items-center p-2 bg-white dark:bg-slate-900 rounded-lg border border-gray-100 dark:border-slate-700">
                                     <span className="text-xs font-mono text-slate-600 dark:text-slate-400">{k.label}</span>
                                     <span className="text-[10px] px-2 py-1 bg-green-100 text-green-700 rounded-full">Valid</span>
                                 </div>
                             ))}
                        </div>
                    </div>
                </div>
            </Modal>

            {toastMessage && <Toast message={toastMessage} onClose={() => setToastMessage(null)} />}
            {isAnalyzing && <AINeuralLoader message={loadingMessage} />}
            <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />
            <RecallModal isOpen={showRecallModal} onClose={() => setShowRecallModal(false)} onRestore={() => {}} />
            <ReferenceClauseModal isOpen={showReferenceModal} onClose={() => setShowReferenceModal(false)} clause={referenceClause} standardName={standards[standardKey]?.name} fullText={referenceText} isLoading={isReferenceLoading} onInsert={(text) => setEvidence(prev => prev + "\n\n" + text)} />
            <CommandPaletteModal isOpen={showCommandPalette} onClose={() => setShowCommandPalette(false)} actions={[]} onSelectAction={() => {}} />
            <SnowOverlay />
        </div>
    );
};

export default App;

