        setFinalReportText(snap.data.finalReportText);
        setShowRecallModal(false);
        setToastMsg(`Session restored to ${new Date(snap.timestamp).toLocaleTimeString()}`);
    };

    const handleNewSession = (e: React.MouseEvent) => {
        if (confirm("Start New Session? Current data will be archived in Recall history.")) {
            // Archive current
            const historyRaw = localStorage.getItem("iso_session_history");
            const history = historyRaw ? JSON.parse(historyRaw) : [];
            const snapshot: SessionSnapshot = {
