import React, { useState } from 'react';
import { Modal, Icon } from './UI';
import { ApiKeyProfile } from '../types';
import { validateApiKey } from '../services/geminiService';
import { MODEL_HIERARCHY } from '../constants';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    apiKeys: ApiKeyProfile[];
    setApiKeys: React.Dispatch<React.SetStateAction<ApiKeyProfile[]>>;
    activeKeyId: string;
    setActiveKeyId: (id: string) => void;
    isAutoCheckEnabled: boolean;
    toggleAutoCheck: (enabled: boolean) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ 
    isOpen, onClose, apiKeys, setApiKeys, activeKeyId, setActiveKeyId, isAutoCheckEnabled, toggleAutoCheck 
}) => {
    const [newKeyInput, setNewKeyInput] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);
    const [editingKeyId, setEditingKeyId] = useState<string | null>(null);
    const [editLabelInput, setEditLabelInput] = useState("");

    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        if (apiKeys.some(k => k.key === newKeyInput.trim())) { 
            alert("This API Key is already in your pool!"); 
            setNewKeyInput(""); 
            return; 
        }
        setIsCheckingKey(true);

        // Initial quick check with default model
        const result = await validateApiKey(newKeyInput);

        const newProfile: ApiKeyProfile = {
            id: Date.now().toString(),
            label: `Key ${apiKeys.length + 1}`,
            key: newKeyInput,
            status: result.isValid ? 'valid' : (result.errorType || 'invalid'),
            latency: result.latency,
            lastChecked: new Date().toISOString(),
            lastError: result.errorMessage
        };

        const newKeys = [...apiKeys, newProfile];
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        // If it's the first valid key, make it active
        if (result.isValid && (!activeKeyId || apiKeys.every(k => k.status !== 'valid'))) {
            setActiveKeyId(newProfile.id);
            localStorage.setItem("iso_active_key_id", newProfile.id);
            localStorage.setItem("iso_api_key", newProfile.key);
        }

        setNewKeyInput("");
        setIsCheckingKey(false);
    };

    const handleDeleteKey = (id: string) => {
        const newKeys = apiKeys.filter(k => k.id !== id);
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        if (activeKeyId === id) {
            const nextValid = newKeys.find(k => k.status === 'valid');
            setActiveKeyId(nextValid?.id || "");
            localStorage.setItem("iso_active_key_id", nextValid?.id || "");
            if (nextValid) localStorage.setItem("iso_api_key", nextValid.key);
        }
    };

    const handleStartEdit = (k: ApiKeyProfile) => {
        setEditingKeyId(k.id);
        setEditLabelInput(k.label);
    };

    const handleSaveLabel = () => {
        if (!editingKeyId) return;
        const newKeys = apiKeys.map(k => k.id === editingKeyId ? { ...k, label: editLabelInput } : k);
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));
        setEditingKeyId(null);
    };

    const handleRefreshStatus = async (id: string) => {
        const keyProfile = apiKeys.find(k => k.id === id);
        if (!keyProfile) return;

        const updatedKeysCheck = apiKeys.map(k => k.id === id ? { ...k, status: 'checking' as const } : k);
        setApiKeys(updatedKeysCheck);

        const res = await validateApiKey(keyProfile.key);

        const finalKeys = apiKeys.map(k => k.id === id ? { 
            ...k, 
            status: res.isValid ? 'valid' : (res.errorType || 'invalid') as any, 
            latency: res.latency, 
            lastChecked: new Date().toISOString(),
            lastError: res.errorMessage 
        } : k);

        setApiKeys(finalKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(finalKeys));
    };

    return (
        <Modal isOpen={isOpen} title="Settings & Neural Network" onClose={onClose}>
            <div className="space-y-6">
                <div className="bg-gray-50 dark:bg-slate-800 p-4 rounded-2xl border border-gray-100 dark:border-slate-700 dark:shadow-[inset_0_1px_3px_rgba(0,0,0,0.5)]">
                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">API Key Pool Management</h4>
                    <div className="flex gap-2 mb-4">
                        <input 
                            type="password" 
                            placeholder="Paste Google Gemini API Key here..." 
                            className="flex-1 p-3 bg-white dark:bg-black border-2 border-indigo-100 dark:border-indigo-900 rounded-xl text-sm font-bold text-slate-900 dark:text-white placeholder-slate-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/20 transition-all shadow-inner"
                            value={newKeyInput}
                            onChange={(e) => setNewKeyInput(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddKey()}
                        />
                        <button onClick={handleAddKey} disabled={isCheckingKey} className="px-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs disabled:opacity-50 transition-colors shadow-lg shadow-indigo-500/30">
                            {isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Plus" size={20}/>}
                        </button>
                    </div>
                    <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar">
                        {apiKeys.map(k => (
                            <div key={k.id} className="flex flex-col gap-1">
                                <div className={`flex items-center justify-between p-2 rounded-xl border ${k.id === activeKeyId ? 'bg-indigo-50 border-indigo-200 dark:bg-indigo-900/20 dark:border-indigo-800' : 'bg-white border-gray-100 dark:bg-slate-900 dark:border-slate-800'}`}>
                                    <div className="flex items-center gap-2 min-w-0">
                                        <div className="relative group/status">
                                            <div className={`w-2 h-2 rounded-full ${k.status === 'valid' ? 'bg-emerald-500' : k.status === 'checking' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500'}`}></div>
                                        </div>
                                        <div className="flex flex-col min-w-0">
                                            {editingKeyId === k.id ? (
                                                <input autoFocus className="text-xs bg-transparent border-b border-indigo-500 outline-none w-20" value={editLabelInput} onChange={e => setEditLabelInput(e.target.value)} onBlur={handleSaveLabel} onKeyDown={e => e.key === 'Enter' && handleSaveLabel()} />
                                            ) : (
                                                <span onClick={() => handleStartEdit(k)} className="text-xs font-bold truncate cursor-pointer hover:text-indigo-500">{k.label}</span>
                                            )}
                                            <span className="text-[10px] text-slate-400 font-mono truncate">{k.key.substring(0, 8)}...</span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-1">
                                        {k.activeModel && <span className="text-[9px] bg-slate-100 dark:bg-slate-800 px-1 rounded text-slate-500">{k.activeModel.split('-')[1]}</span>}
                                        <button onClick={() => handleRefreshStatus(k.id)} className="p-1.5 text-slate-400 hover:text-indigo-500" title="Refresh Status"><Icon name="RefreshCw" size={14}/></button>
                                        <button onClick={() => handleDeleteKey(k.id)} className="p-1.5 text-slate-400 hover:text-red-500" title="Delete Key"><Icon name="Trash2" size={14}/></button>
                                    </div>
                                </div>
                                {/* Specific Error Display */}
                                {k.status !== 'valid' && k.status !== 'checking' && k.lastError && (
                                    <div className="ml-4 text-[9px] text-red-500 font-mono bg-red-50 dark:bg-red-900/10 p-1.5 rounded border border-red-100 dark:border-red-900/30 flex items-start gap-1">
                                        <Icon name="AlertCircle" size={10} className="mt-0.5 shrink-0"/>
                                        <span className="break-all">{k.lastError}</span>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                     <div className="mt-4 text-xs text-slate-400 dark:text-slate-500 bg-gray-100 dark:bg-slate-800/50 p-2 rounded-lg text-center leading-relaxed">
                        <Icon name="Info" size={14} className="inline mr-1"/>
                        Ensure your key has <strong>Generative Language API</strong> enabled in Google Cloud Console.
                    </div>
                </div>
                <div className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 dark:shadow-md">
                    <div className="flex items-center gap-3">
                        <Icon name="Session10_Pulse" size={20} className="text-cyan-500"/>
                        <div>
                            <h5 className="text-sm font-bold text-slate-800 dark:text-slate-200">Auto Health Check</h5>
                            <p className="text-xs text-slate-500 dark:text-slate-400">Periodically validate API keys in background.</p>
                        </div>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" checked={isAutoCheckEnabled} onChange={(e) => toggleAutoCheck(e.target.checked)} className="sr-only peer" />
                        <div className="w-11 h-6 bg-gray-200 dark:bg-slate-700 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-indigo-600"></div>
                    </label>
                </div>
            </div>
        </Modal>
    );
};

export default SettingsModal;

