    const [isSaving, setIsSaving] = useState(false); 
    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);

    // Reference Modal State
    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean;
        clause: Clause | null;
        fullText: { en: string; vi: string };
        isLoading: boolean;
    }>({ isOpen: false, clause: null, fullText: { en: "", vi: "" }, isLoading: false });

    // Export State
    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 

    // Drag & Drop
    const [isDragging, setIsDragging] = useState(false);
    const [templateFileName, setTemplateFileName] = useState<string>("");

    // Audit Data
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);

    // Analysis Data
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading States
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });

    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidence = evidence.trim().length > 0 || uploadedFiles.length > 0;
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);

    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);
    const isSystemHealthy = activeKeyProfile?.status === 'valid';

    // --- EFFECT: Load Keys ---
    useEffect(() => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            let loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];

            // Inject fixed keys if missing
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (!existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ 
                        id: `fixed_${index}`, 
                        label: `Fixed Key ${index + 1}`, 
                        key: fixedKey, 
                        status: 'unknown', 
                        latency: 0, 
                        lastChecked: new Date().toISOString() 
                    });
                    hasChanges = true;
                }
            });

            if (hasChanges) {
                localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));
            }
            setApiKeys(loadedKeys);

            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) {
                setActiveKeyId(savedActiveId);
            } else if (loadedKeys.length > 0) {
                setActiveKeyId(loadedKeys[0].id);
            }
        } catch (e) { console.error("Key load error", e); }
    }, []);

    // --- EFFECT: Dark Mode Class ---
    useEffect(() => {
        if (isDarkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [isDarkMode]);

    // --- HELPERS ---
    const dismissError = () => { 
        setIsErrorClosing(true); 
        setTimeout(() => { setAiError(null); setIsErrorClosing(false); }, 300); 
    };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys exhausted."); setShowSettingsModal(true); }
        else if (msg.includes("API Key is missing")) { setToastMsg("API Key required."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.id === activeKeyId) return -1;
            return 0;
        });

        if (candidates.length === 0) throw new Error("No valid API Keys found. Please add one in Settings.");

        let lastError: any;
        for (const profile of candidates) {
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                const result = await operation(profile.key, MODEL_HIERARCHY[0]);
                return result;
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed:`, error); 
                lastError = error;
                // Update key status if it's a hard error
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota")) {
                    setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded', lastError: error.message } : k));
                } else if (msg.includes("403") || msg.includes("key not valid")) {
                    setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid', lastError: error.message } : k));
                }
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    // --- HANDLERS ---
    const handleUpdateStandard = (std: any) => setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    const handleResetStandard = (key: string) => {
        setCustomStandards(prev => { const n = { ...prev }; delete n[key]; return n; });
    };

    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, fullText: { en: "", vi: "" }, isLoading: true });
        try {
            const text = await executeWithSmartFailover((key, model) => fetchFullClauseText({ code: clause.code, title: clause.title }, allStandards[standardKey]?.name, key, model));
            setReferenceClauseState(prev => ({ ...prev, fullText: text, isLoading: false }));
        } catch (e: any) {
            handleGenericError(e);
            setReferenceClauseState(prev => ({ ...prev, isLoading: false, fullText: { en: "Error loading text.", vi: "" } }));
        }
    };

    const handleInsertReferenceText = (text: string) => {
        setEvidence(prev => prev + `\n> **Reference (${referenceClauseState.clause?.code}):**\n> ${text.replace(/\n/g, '\n> ')}`);
        setReferenceClauseState(prev => ({ ...prev, isOpen: false }));
    };

    const handleAnalyze = async () => {
        if (!isReadyForAnalysis) return;
        setIsAnalyzeLoading(true); setAnalysisResult([]); setLayoutMode('findings');
        const allClauses = allStandards[standardKey].groups.flatMap(g => g.clauses);
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { if (c.id === id) return c; if (c.subClauses) { const f = findClause(id, c.subClauses); if (f) return f; } }
        };
        const clausesToAnalyze = selectedClauses.map(id => findClause(id, allClauses)).filter(c => !!c) as Clause[];
        const fullEvidence = evidence + "\n" + uploadedFiles.filter(f => f.status === 'success').map(f => `--- ${f.file.name} ---\n${f.result}`).join('\n');

        try {
            for (const clause of clausesToAnalyze) {
                setCurrentAnalyzingClause(`${clause.code} ${clause.title}`);
                setLoadingMessage("Checking compliance...");
                const prompt = `Analyze evidence against ISO Clause ${clause.code}: ${clause.title} (${clause.description}). Evidence: ${fullEvidence.substring(0, 15000)}... Provide JSON result.`;
                const instruction = `You are a strict ISO Lead Auditor. Return JSON array.`;
                const jsonStr = await executeWithSmartFailover((key, model) => generateAnalysis(prompt, instruction, key, model));
                const res = cleanAndParseJSON(jsonStr);
                if (Array.isArray(res) && res.length > 0) {
                    setAnalysisResult(prev => [...(prev || []), { ...res[0], clauseId: clause.code }]);
                }
                await new Promise(r => setTimeout(r, 500));
            }
        } catch (e: any) { handleGenericError(e); } 
        finally { setIsAnalyzeLoading(false); setCurrentAnalyzingClause(""); }
    };

    // Badge Logic
    const badgeColorClass = useMemo(() => {
        if (standardKey.includes('9001')) return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
        return 'bg-gray-100 text-gray-700 border-gray-200 dark:bg-gray-800 dark:text-gray-300 dark:border-gray-700';
    }, [standardKey]);
    const displayBadge = standardKey ? (allStandards[standardKey]?.name.split(' ')[0] + " " + allStandards[standardKey]?.name.split(' ')[1]) : "NO STANDARD";

    // Tab Animation
    useEffect(() => {
        const idx = ['evidence', 'findings', 'report'].indexOf(layoutMode);
        if (idx !== -1 && tabsRef.current[idx]) {
            const el = tabsRef.current[idx];
            if (el) {
                setTabStyle({ left: el.offsetLeft, width: el.offsetWidth, opacity: 1, color: '' });
            }
        }
    }, [layoutMode, isSidebarOpen]);

    return (
        <div className="flex flex-col h-screen w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 overflow-hidden text-sm md:text-base">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}
            {aiError && (
                <div className={`fixed z-[9999] top-20 right-5 bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl p-4 rounded-r-xl animate-shake transition-all duration-300 ${isErrorClosing ? 'opacity-0' : 'opacity-100'}`}>
                    <div className="flex justify-between items-start gap-3">
                        <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>Error</span></div>
                        <button onClick={dismissError}><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 mt-1">{aiError}</p>
                </div>
            )}

            {/* Header */}
            <header className="flex-shrink-0 h-14 md:h-16 px-4 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex justify-between items-center z-[70]">
                <div className="flex items-center gap-3">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg">
                        <Icon name="LayoutList" size={24}/>
                    </button>
                    <div className="flex items-center gap-2">
                        <h1 className="hidden md:block text-lg font-bold text-slate-900 dark:text-white">ISO Audit Pro</h1>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${badgeColorClass}`}>{displayBadge}</span>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg"><Icon name="Session6_Zap" size={20}/></button>
                    <div className="hidden md:block"><FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: any) => setFontSizeScale((p: number) => dir==='increase'?p+0.1:p-0.1)} /></div>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg"><Icon name={isDarkMode ? "Sun" : "Moon"} size={20}/></button>
                    <button onClick={() => setShowSettingsModal(true)} className="relative p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg">
                        <Icon name="Settings" size={20}/>
                        {!isSystemHealthy && <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>}
                    </button>
                </div>
            </header>

            {/* Main Layout: Flex Row to force side-by-side */}
            <div className="flex-1 flex overflow-hidden relative">
                {/* Sidebar Container */}
                <div className={`${isSidebarOpen ? 'w-full md:w-[400px] border-r' : 'w-0 border-none'} flex-shrink-0 transition-[width] duration-300 bg-white dark:bg-slate-900 overflow-hidden flex flex-col z-20 absolute md:relative h-full`}>
                    <Sidebar 
                        key={sessionKey} 
                        isOpen={isSidebarOpen} 
                        width={sidebarWidth} 
                        setWidth={setSidebarWidth} 
                        standards={allStandards} 
                        standardKey={standardKey} 
                        setStandardKey={setStandardKey} 
                        auditInfo={auditInfo} 
                        setAuditInfo={setAuditInfo} 
                        selectedClauses={selectedClauses} 
                        setSelectedClauses={setSelectedClauses} 
                        onAddNewStandard={() => {}} 
                        onUpdateStandard={handleUpdateStandard} 
                        onResetStandard={handleResetStandard} 
                        onReferenceClause={handleOpenReferenceClause} 
                        showIntegrityModal={showIntegrityModal} 
                        setShowIntegrityModal={setShowIntegrityModal}
                    />
                </div>

                {/* Main Content */}
                <main className="flex-1 flex flex-col min-w-0 bg-gray-50 dark:bg-slate-950/50 relative">
                    {/* Tabs Header */}
                    <div className="flex-shrink-0 p-2 md:p-4 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-2">
                        <div className="flex-1 bg-gray-100 dark:bg-slate-950 p-1 rounded-xl flex relative" ref={tabsContainerRef}>
                            <div className="absolute top-1 bottom-1 bg-white dark:bg-slate-800 rounded-lg shadow-sm transition-all duration-300" style={tabStyle}></div>
                            {tabsList.map((tab, idx) => (
                                <button key={tab.id} ref={el => { tabsRef.current[idx] = el }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className="flex-1 relative z-10 py-2 text-xs md:text-sm font-bold text-center flex items-center justify-center gap-2 text-slate-500 dark:text-slate-400">
                                    <Icon name={tab.icon} size={16}/> <span className="hidden md:inline">{tab.label}</span>
                                </button>
                            ))}
                        </div>
                        <button onClick={() => setShowRecallModal(true)} className="p-2 bg-white dark:bg-slate-800 border rounded-xl shadow-sm text-slate-500 hover:text-indigo-600"><Icon name="History" size={20}/></button>
                    </div>

                    {/* Content Body */}
                    <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className={`flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-200 dark:border-transparent p-4 flex flex-col ${isDragging ? 'ring-2 ring-indigo-500' : ''}`} onDragOver={e => {e.preventDefault(); setIsDragging(true)}} onDragLeave={() => setIsDragging(false)}>
                                    <textarea 
                                        ref={evidenceTextareaRef}
                                        className="flex-1 w-full bg-transparent outline-none resize-none text-slate-700 dark:text-slate-300 text-sm leading-relaxed" 
                                        placeholder="Paste audit evidence here..." 
                                        value={evidence} 
                                        onChange={e => setEvidence(e.target.value)}
                                    />
                                    {isDragging && <div className="absolute inset-0 bg-indigo-50/90 flex items-center justify-center text-indigo-600 font-bold">Drop Files Here</div>}
                                </div>
                                <div className="flex justify-end gap-2">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg disabled:opacity-50 flex items-center gap-2">
                                        {isAnalyzeLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>} Analyze
                                    </button>
                                </div>
                            </div>
                        )}

                        {layoutMode === 'findings' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 overflow-y-auto custom-scrollbar p-1 space-y-3">
                                    {!analysisResult && <div className="text-center text-slate-400 mt-20">No analysis results yet.</div>}
                                    {analysisResult?.map((item, idx) => (
                                        <div key={idx} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl p-4 shadow-sm">
                                            <div className="flex justify-between mb-2">
                                                <span className="font-bold text-indigo-600 bg-indigo-50 dark:bg-indigo-900/20 px-2 rounded">{item.clauseId}</span>
                                                <span className={`font-bold px-2 rounded ${item.status === 'COMPLIANT' ? 'text-emerald-600 bg-emerald-50' : 'text-red-600 bg-red-50'}`}>{item.status}</span>
                                            </div>
                                            <p className="text-sm text-slate-700 dark:text-slate-300">{item.reason}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {layoutMode === 'report' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-200 dark:border-transparent p-4 relative">
                                    <textarea className="w-full h-full bg-transparent outline-none resize-none font-mono text-sm text-slate-700 dark:text-slate-300" value={finalReportText || ""} onChange={e => setFinalReportText(e.target.value)} placeholder="Generated report will appear here..."/>
                                    {isReportLoading && <AINeuralLoader message={loadingMessage}/>}
                                </div>
                                <div className="flex justify-end">
                                    <button onClick={handleGenerateReport} disabled={!isReadyToSynthesize} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg disabled:opacity-50">Synthesize Report</button>
                                </div>
                            </div>
                        )}
                    </div>
                </main>
            </div>

            {/* Modals */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={() => setIsCmdPaletteOpen(false)} actions={commandActions} onSelectAction={(a: any) => a.action()}/>
            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />
            <ReferenceClauseModal isOpen={referenceClauseState.isOpen} onClose={() => setReferenceClauseState(p => ({...p, isOpen: false}))} clause={referenceClauseState.clause} standardName={allStandards[standardKey]?.name} fullText={referenceClauseState.fullText} isLoading={referenceClauseState.isLoading} onInsert={handleInsertReferenceText}/>
            <RecallModal isOpen={showRecallModal} onClose={() => setShowRecallModal(false)} onRestore={handleRestoreSnapshot}/>

            {/* New Settings Modal */}
            <SettingsModal 
                isOpen={showSettingsModal} 
                onClose={() => setShowSettingsModal(false)}
                apiKeys={apiKeys}
                setApiKeys={setApiKeys}
                activeKeyId={activeKeyId}
                setActiveKeyId={setActiveKeyId}
                isAutoCheckEnabled={isAutoCheckEnabled}
                toggleAutoCheck={setIsAutoCheckEnabled}
            />
        </div>
    );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE, MODEL_HIERARCHY, MY_FIXED_KEYS, DEFAULT_AUDIT_INFO } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, ApiKeyProfile, Clause, FindingsViewMode, SessionSnapshot } from './types';
import { Icon, FontSizeController, SparkleLoader, AINeuralLoader, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import RecallModal from './components/RecallModal';
import SettingsModal from './components/SettingsModal';
import { generateOcrContent, generateAnalysis, generateTextReport, validateApiKey, fetchFullClauseText } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64, cleanFileName } from './utils';

type LayoutMode = 'evidence' | 'findings' | 'report' | 'split';
type ExportLanguage = 'en' | 'vi';

interface UploadedFile {
    id: string;
    file: File;
    status: 'pending' | 'processing' | 'success' | 'error';
    error?: string;
    result?: string;
}

export default function App() {
    // -- STATE --
    const [sessionKey, setSessionKey] = useState(Date.now());

    // UI Config
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420); 
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);

    // Modals
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [showRecallModal, setShowRecallModal] = useState(false); 
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);

    // Data View
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');

    // API Keys
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);
    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);

    // Notifications & Status
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [lastSavedTime, setLastSavedTime] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false); 
    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);

    // Reference Modal State
    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean;
        clause: Clause | null;
        fullText: { en: string; vi: string };
        isLoading: boolean;
    }>({ isOpen: false, clause: null, fullText: { en: "", vi: "" }, isLoading: false });

    // Export State
    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 

    // Drag & Drop
    const [isDragging, setIsDragging] = useState(false);
    const [templateFileName, setTemplateFileName] = useState<string>("");

    // Audit Data
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);

    // Analysis Data
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading States
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });

    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidence = evidence.trim().length > 0 || uploadedFiles.length > 0;
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);

    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);
    const isSystemHealthy = activeKeyProfile?.status === 'valid';

    // --- EFFECT: Load Keys ---
    useEffect(() => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            let loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];

            // Inject fixed keys if missing
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (!existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ 
                        id: `fixed_${index}`, 
                        label: `Fixed Key ${index + 1}`, 
                        key: fixedKey, 
                        status: 'unknown', 
                        latency: 0, 
                        lastChecked: new Date().toISOString() 
                    });
                    hasChanges = true;
                }
            });

            if (hasChanges) {
                localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));
            }
            setApiKeys(loadedKeys);

            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) {
                setActiveKeyId(savedActiveId);
            } else if (loadedKeys.length > 0) {
                setActiveKeyId(loadedKeys[0].id);
            }
        } catch (e) { console.error("Key load error", e); }
    }, []);

    // --- EFFECT: Dark Mode Class ---
    useEffect(() => {
        if (isDarkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [isDarkMode]);

    // --- EFFECT: Auto-select findings when analysis is done ---
    useEffect(() => {
        if (analysisResult && analysisResult.length > 0) {
            const initialSelection: Record<string, boolean> = {};
            analysisResult.forEach(r => { initialSelection[r.clauseId] = true; });
            setSelectedFindings(initialSelection);
        }
    }, [analysisResult]);

    // --- HELPERS ---
    const dismissError = () => { 
        setIsErrorClosing(true); 
        setTimeout(() => { setAiError(null); setIsErrorClosing(false); }, 300); 
    };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys exhausted."); setShowSettingsModal(true); }
        else if (msg.includes("API Key is missing")) { setToastMsg("API Key required."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.id === activeKeyId) return -1;
            return 0;
        });

        if (candidates.length === 0) throw new Error("No valid API Keys found. Please add one in Settings.");

        let lastError: any;
        for (const profile of candidates) {
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                const result = await operation(profile.key, MODEL_HIERARCHY[0]);
                return result;
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed:`, error); 
                lastError = error;
                // Update key status if it's a hard error
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota")) {
                    setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded', lastError: error.message } : k));
                } else if (msg.includes("403") || msg.includes("key not valid")) {
                    setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid', lastError: error.message } : k));
                }
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    // --- HANDLERS ---
    const handleUpdateStandard = (std: any) => setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    const handleResetStandard = (key: string) => {
        setCustomStandards(prev => { const n = { ...prev }; delete n[key]; return n; });
    };

    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, fullText: { en: "", vi: "" }, isLoading: true });
        try {
            const text = await executeWithSmartFailover((key, model) => fetchFullClauseText({ code: clause.code, title: clause.title }, allStandards[standardKey]?.name, key, model));
            setReferenceClauseState(prev => ({ ...prev, fullText: text, isLoading: false }));
        } catch (e: any) {
            handleGenericError(e);
            setReferenceClauseState(prev => ({ ...prev, isLoading: false, fullText: { en: "Error loading text.", vi: "" } }));
        }
    };

    const handleInsertReferenceText = (text: string) => {
        setEvidence(prev => prev + `\n> **Reference (${referenceClauseState.clause?.code}):**\n> ${text.replace(/\n/g, '\n> ')}`);
        setReferenceClauseState(prev => ({ ...prev, isOpen: false }));
    };

    const handleAnalyze = async () => {
        if (!isReadyForAnalysis) return;
        setIsAnalyzeLoading(true); setAnalysisResult([]); setLayoutMode('findings');
        const allClauses = allStandards[standardKey].groups.flatMap(g => g.clauses);
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { if (c.id === id) return c; if (c.subClauses) { const f = findClause(id, c.subClauses); if (f) return f; } }
        };
        const clausesToAnalyze = selectedClauses.map(id => findClause(id, allClauses)).filter(c => !!c) as Clause[];
        const fullEvidence = evidence + "\n" + uploadedFiles.filter(f => f.status === 'success').map(f => `--- ${f.file.name} ---\n${f.result}`).join('\n');

        try {
            for (const clause of clausesToAnalyze) {
                setCurrentAnalyzingClause(`${clause.code} ${clause.title}`);
                setLoadingMessage("Checking compliance...");
                const prompt = `Analyze evidence against ISO Clause ${clause.code}: ${clause.title} (${clause.description}). Evidence: ${fullEvidence.substring(0, 15000)}... Provide JSON result.`;
                const instruction = `You are a strict ISO Lead Auditor. Return JSON array.`;
                const jsonStr = await executeWithSmartFailover((key, model) => generateAnalysis(prompt, instruction, key, model));
                const res = cleanAndParseJSON(jsonStr);
                if (Array.isArray(res) && res.length > 0) {
                    setAnalysisResult(prev => [...(prev || []), { ...res[0], clauseId: clause.code }]);
                }
                await new Promise(r => setTimeout(r, 500));
            }
        } catch (e: any) { handleGenericError(e); } 
        finally { setIsAnalyzeLoading(false); setCurrentAnalyzingClause(""); }
    };

    const handleGenerateReport = async () => {
        if (!isReadyToSynthesize) return;
        setIsReportLoading(true);
        setLoadingMessage("Synthesizing Final Audit Report...");
        try {
            const findingsText = analysisResult?.filter(f => selectedFindings[f.clauseId]).map(f => 
                `[${f.clauseId}] Status: ${f.status}\nObservation: ${f.reason}\nEvidence: ${f.evidence}\nSuggestion: ${f.suggestion}`
            ).join('\n---\n') || "";

            const prompt = `
            Generate a formal ISO Audit Report based on the following findings.

            AUDIT INFO:
            Company: ${auditInfo.company}
            Standard: ${allStandards[standardKey]?.name || standardKey}
            Type: ${auditInfo.type}
            Auditor: ${auditInfo.auditor}

            FINDINGS:
            ${findingsText}

            REQUIREMENTS:
            1. Professional Tone.
            2. Executive Summary.
            3. Detailed Findings Table.
            4. Conclusion.
            5. Language: ${exportLanguage === 'vi' ? 'Vietnamese' : 'English'}.
            `;

            const systemInstruction = "You are an expert ISO Lead Auditor. Generate a comprehensive audit report in Markdown format.";

            const report = await executeWithSmartFailover((key, model) => generateTextReport(prompt, systemInstruction, key, model));
            setFinalReportText(report);
            setToastMsg("Report generated successfully!");
        } catch (e: any) {
            handleGenericError(e);
        } finally {
            setIsReportLoading(false);
        }
    };

    const handleRestoreSnapshot = (snapshot: SessionSnapshot) => {
        setStandardKey(snapshot.data.standardKey);
        setAuditInfo(snapshot.data.auditInfo);
        setSelectedClauses(snapshot.data.selectedClauses);
        setEvidence(snapshot.data.evidence);
        setAnalysisResult(snapshot.data.analysisResult);
        setSelectedFindings(snapshot.data.selectedFindings);
        setFinalReportText(snapshot.data.finalReportText);
        setToastMsg("Session restored successfully.");
        setShowRecallModal(false);
    };

    const commandActions = [
        { 
            label: "Analyze", 
            desc: "Run compliance analysis", 
            icon: "Wand2", 
            action: () => { 
                if (isReadyForAnalysis) handleAnalyze(); 
                else setToastMsg("Not ready to analyze. Check evidence/clauses.");
                setIsCmdPaletteOpen(false); 
            } 
        },
        { 
            label: "Synthesize Report", 
            desc: "Generate final report from findings", 
            icon: "FilePlus2", 
            action: () => { 
                if (isReadyToSynthesize) { setLayoutMode('report'); handleGenerateReport(); }
                else setToastMsg("Not ready to synthesize.");
                setIsCmdPaletteOpen(false); 
            } 
        },
        { 
            label: "New Session", 
            desc: "Clear current workspace", 
            icon: "FilePlus2", 
            action: () => { 
                if(confirm("Start new session?")) {
                    setEvidence("");
                    setUploadedFiles([]);
                    setSelectedClauses([]);
                    setAnalysisResult(null);
                    setFinalReportText(null);
                    setSessionKey(Date.now());
                }
                setIsCmdPaletteOpen(false); 
            } 
        },
         { 
            label: "Dark Mode Toggle", 
            desc: "Switch theme", 
            icon: isDarkMode ? "Sun" : "Moon", 
            action: () => { setIsDarkMode(!isDarkMode); setIsCmdPaletteOpen(false); } 
        },
        { 
            label: "Settings", 
            desc: "Manage API Keys and Config", 
            icon: "Settings", 
            action: () => { setShowSettingsModal(true); setIsCmdPaletteOpen(false); } 
        }
    ];

    const tabsList = [
        { id: 'evidence', label: 'Evidence Workspace', icon: 'FileText' },
        { id: 'findings', label: 'Compliance Findings', icon: 'Wand2' },
        { id: 'report', label: 'Final Report', icon: 'FilePlus2' }
    ];

    // Badge Logic
    const badgeColorClass = useMemo(() => {
        if (standardKey.includes('9001')) return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
        return 'bg-gray-100 text-gray-700 border-gray-200 dark:bg-gray-800 dark:text-gray-300 dark:border-gray-700';
    }, [standardKey]);
    const displayBadge = standardKey ? (allStandards[standardKey]?.name.split(' ')[0] + " " + allStandards[standardKey]?.name.split(' ')[1]) : "NO STANDARD";

    // Tab Animation
    useEffect(() => {
        const idx = ['evidence', 'findings', 'report'].indexOf(layoutMode);
        if (idx !== -1 && tabsRef.current[idx]) {
            const el = tabsRef.current[idx];
            if (el) {
                setTabStyle({ left: el.offsetLeft, width: el.offsetWidth, opacity: 1, color: '' });
            }
        }
    }, [layoutMode, isSidebarOpen]);

    return (
        <div className="flex flex-col h-screen w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 overflow-hidden text-sm md:text-base">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}
            {aiError && (
                <div className={`fixed z-[9999] top-20 right-5 bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl p-4 rounded-r-xl animate-shake transition-all duration-300 ${isErrorClosing ? 'opacity-0' : 'opacity-100'}`}>
                    <div className="flex justify-between items-start gap-3">
                        <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>Error</span></div>
                        <button onClick={dismissError}><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 mt-1">{aiError}</p>
                </div>
            )}

            {/* Header */}
            <header className="flex-shrink-0 h-14 md:h-16 px-4 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex justify-between items-center z-[70]">
                <div className="flex items-center gap-3">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg">
                        <Icon name="LayoutList" size={24}/>
                    </button>
                    <div className="flex items-center gap-2">
                        <h1 className="hidden md:block text-lg font-bold text-slate-900 dark:text-white">ISO Audit Pro</h1>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${badgeColorClass}`}>{displayBadge}</span>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg"><Icon name="Session6_Zap" size={20}/></button>
                    <div className="hidden md:block"><FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: any) => setFontSizeScale((p: number) => dir==='increase'?p+0.1:p-0.1)} /></div>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg"><Icon name={isDarkMode ? "Sun" : "Moon"} size={20}/></button>
                    <button onClick={() => setShowSettingsModal(true)} className="relative p-2 text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg">
                        <Icon name="Settings" size={20}/>
                        {!isSystemHealthy && <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>}
                    </button>
                </div>
            </header>

            {/* Main Layout: Flex Row to force side-by-side */}
            <div className="flex-1 flex overflow-hidden relative">
                {/* Sidebar Container */}
                <div className={`${isSidebarOpen ? 'w-full md:w-[400px] border-r' : 'w-0 border-none'} flex-shrink-0 transition-[width] duration-300 bg-white dark:bg-slate-900 overflow-hidden flex flex-col z-20 absolute md:relative h-full`}>
                    <Sidebar 
                        key={sessionKey} 
                        isOpen={isSidebarOpen} 
                        width={sidebarWidth} 
                        setWidth={setSidebarWidth} 
                        standards={allStandards} 
                        standardKey={standardKey} 
                        setStandardKey={setStandardKey} 
                        auditInfo={auditInfo} 
                        setAuditInfo={setAuditInfo} 
                        selectedClauses={selectedClauses} 
                        setSelectedClauses={setSelectedClauses} 
                        onAddNewStandard={() => {}} 
                        onUpdateStandard={handleUpdateStandard} 
                        onResetStandard={handleResetStandard} 
                        onReferenceClause={handleOpenReferenceClause} 
                        showIntegrityModal={showIntegrityModal} 
                        setShowIntegrityModal={setShowIntegrityModal}
                    />
                </div>

                {/* Main Content */}
                <main className="flex-1 flex flex-col min-w-0 bg-gray-50 dark:bg-slate-950/50 relative">
                    {/* Tabs Header */}
                    <div className="flex-shrink-0 p-2 md:p-4 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-2">
                        <div className="flex-1 bg-gray-100 dark:bg-slate-950 p-1 rounded-xl flex relative" ref={tabsContainerRef}>
                            <div className="absolute top-1 bottom-1 bg-white dark:bg-slate-800 rounded-lg shadow-sm transition-all duration-300" style={tabStyle}></div>
                            {tabsList.map((tab, idx) => (
                                <button key={tab.id} ref={el => { tabsRef.current[idx] = el }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className="flex-1 relative z-10 py-2 text-xs md:text-sm font-bold text-center flex items-center justify-center gap-2 text-slate-500 dark:text-slate-400">
                                    <Icon name={tab.icon} size={16}/> <span className="hidden md:inline">{tab.label}</span>
                                </button>
                            ))}
                        </div>
                        <button onClick={() => setShowRecallModal(true)} className="p-2 bg-white dark:bg-slate-800 border rounded-xl shadow-sm text-slate-500 hover:text-indigo-600"><Icon name="History" size={20}/></button>
                    </div>

                    {/* Content Body */}
                    <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className={`flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-200 dark:border-transparent p-4 flex flex-col ${isDragging ? 'ring-2 ring-indigo-500' : ''}`} onDragOver={e => {e.preventDefault(); setIsDragging(true)}} onDragLeave={() => setIsDragging(false)}>
                                    <textarea 
                                        ref={evidenceTextareaRef}
                                        className="flex-1 w-full bg-transparent outline-none resize-none text-slate-700 dark:text-slate-300 text-sm leading-relaxed" 
                                        placeholder="Paste audit evidence here..." 
                                        value={evidence} 
                                        onChange={e => setEvidence(e.target.value)}
                                    />
                                    {isDragging && <div className="absolute inset-0 bg-indigo-50/90 flex items-center justify-center text-indigo-600 font-bold">Drop Files Here</div>}
                                </div>
                                <div className="flex justify-end gap-2">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg disabled:opacity-50 flex items-center gap-2">
                                        {isAnalyzeLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>} Analyze
                                    </button>
                                </div>
                            </div>
                        )}

                        {layoutMode === 'findings' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 overflow-y-auto custom-scrollbar p-1 space-y-3">
                                    {!analysisResult && <div className="text-center text-slate-400 mt-20">No analysis results yet.</div>}
                                    {analysisResult?.map((item, idx) => (
                                        <div key={idx} className="bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl p-4 shadow-sm">
                                            <div className="flex justify-between mb-2">
                                                <span className="font-bold text-indigo-600 bg-indigo-50 dark:bg-indigo-900/20 px-2 rounded">{item.clauseId}</span>
                                                <span className={`font-bold px-2 rounded ${item.status === 'COMPLIANT' ? 'text-emerald-600 bg-emerald-50' : 'text-red-600 bg-red-50'}`}>{item.status}</span>
                                            </div>
                                            <p className="text-sm text-slate-700 dark:text-slate-300">{item.reason}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {layoutMode === 'report' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-200 dark:border-transparent p-4 relative">
                                    <textarea className="w-full h-full bg-transparent outline-none resize-none font-mono text-sm text-slate-700 dark:text-slate-300" value={finalReportText || ""} onChange={e => setFinalReportText(e.target.value)} placeholder="Generated report will appear here..."/>
                                    {isReportLoading && <AINeuralLoader message={loadingMessage}/>}
                                </div>
                                <div className="flex justify-end">
                                    <button onClick={handleGenerateReport} disabled={!isReadyToSynthesize} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg disabled:opacity-50">Synthesize Report</button>
                                </div>
                            </div>
                        )}
                    </div>
                </main>
            </div>

            {/* Modals */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={() => setIsCmdPaletteOpen(false)} actions={commandActions} onSelectAction={(a: any) => a.action()}/>
            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />
            <ReferenceClauseModal isOpen={referenceClauseState.isOpen} onClose={() => setReferenceClauseState(p => ({...p, isOpen: false}))} clause={referenceClauseState.clause} standardName={allStandards[standardKey]?.name} fullText={referenceClauseState.fullText} isLoading={referenceClauseState.isLoading} onInsert={handleInsertReferenceText}/>
            <RecallModal isOpen={showRecallModal} onClose={() => setShowRecallModal(false)} onRestore={handleRestoreSnapshot}/>

            {/* New Settings Modal */}
            <SettingsModal 
                isOpen={showSettingsModal} 
                onClose={() => setShowSettingsModal(false)}
                apiKeys={apiKeys}
                setApiKeys={setApiKeys}
                activeKeyId={activeKeyId}
                setActiveKeyId={setActiveKeyId}
                isAutoCheckEnabled={isAutoCheckEnabled}
                toggleAutoCheck={setIsAutoCheckEnabled}
            />
        </div>
    );
}
